jac_code:
"""Converted adjacency lookup into Jac graph traversal."""

node LabelNode {
    has label: str = "";
}

walker NeighborLabels {
    has labels: list[str] = [];

    can collect with LabelNode entry {
        visit [-->][?:LabelNode];
        if here.label != "a" {
            self.labels.append(here.label);
        }
    }
}

with entry {
    a = LabelNode(label="a");
    b = LabelNode(label="b");
    root() ++> a;
    a ++> b;
    result = root() spawn NeighborLabels();
    print(result);
}

